// Lista plana 'Dirección Regional · NN' para combobox.
export const ALL_CIRCUITS: string[] = MEP_REGIONAL_DIRECTIONS.flatMap(
  (dr) => dr.circuits.map((c) => `${dr.name} · ${c}`)
)

// Mapa: 'Dirección Regional · NN' → 'Dirección Regional'.
export const CIRCUIT_TO_REGION: Record<string, string> = Object.fromEntries(
  MEP_REGIONAL_DIRECTIONS.flatMap((dr) =>
    dr.circuits.map((c) => [`${dr.name} · ${c}`, dr.name])
  )
)

